import json
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        
        for enrich_url in enrich_urls:
            url = enrich_url['value']
            try:
                response = requests.get(url)
                if response.status_code == 200:
                    # Assuming JSON data, modify this if needed for other formats
                    enrich_data = response.json()
                    # Add enriched data to request headers if needed
                    headers['x-enrich-data'] = [{'key': 'x-enrich-data', 'value': json.dumps(enrich_data)}]
            except requests.RequestException as e:
                # Handle any request exceptions as per your requirements
                pass
    
    return request